import type { Control, ControlStatus, FrameworkMapping } from "@/types";

// ---------------------------------------------------------------------------
// Control library (spec §14): 100+ original, concise governance controls.
// Stored as data and expanded through a builder so the catalogue stays
// readable while every record remains complete.
// ---------------------------------------------------------------------------

interface ControlSeed {
  id: string;
  t: string; // title
  dom: string;
  cap: string;
  obj: string; // objective
  stmt: string; // control statement
  why: string; // rationale
  min: string; // minimum implementation
  adv: string; // advanced implementation
  ev: string[]; // evidence examples
  test: string; // testing procedure
  owner: string;
  reviewer: string;
  freq: string;
  fw?: string[]; // "frameworkId:reference"
  req?: boolean; // required (default true)
  dg?: boolean;
  ai?: boolean;
  gen?: boolean;
  appl?: string[];
  juris?: string[];
  ind?: string[];
  deps?: string[];
}

function fwMap(items?: string[]): FrameworkMapping[] {
  if (!items) return [];
  return items.map((s) => {
    const [frameworkId, ...rest] = s.split(":");
    return { frameworkId, reference: rest.join(":") };
  });
}

// A spread of realistic operational states so dashboards are meaningful.
const STATUS_CYCLE: ControlStatus[] = [
  "operating",
  "implemented",
  "in_progress",
  "implemented",
  "needs_review",
  "planned",
  "operating",
  "not_implemented",
];

function build(seeds: ControlSeed[]): Control[] {
  return seeds.map((s, i) => {
    const status = STATUS_CYCLE[i % STATUS_CYCLE.length];
    return {
      id: s.id,
      title: s.t,
      domainId: s.dom,
      capabilityId: s.cap,
      objective: s.obj,
      statement: s.stmt,
      rationale: s.why,
      applicability: s.appl ?? ["All organisations in scope"],
      minimumImplementation: s.min,
      advancedImplementation: s.adv,
      owner: s.owner,
      reviewer: s.reviewer,
      frequency: s.freq,
      evidenceExamples: s.ev,
      testingProcedure: s.test,
      dependencies: s.deps ?? [],
      frameworkMappings: fwMap(s.fw),
      jurisdictionTags: s.juris ?? ["Global"],
      industryTags: s.ind ?? ["Cross-industry"],
      dataGovernance: s.dg ?? false,
      aiGovernance: s.ai ?? false,
      genAi: s.gen ?? false,
      required: s.req ?? true,
      status,
      active: true,
      version: 1,
    } satisfies Control;
  });
}

